// Extract LINE message data and classify inquiry
const body = $input.first().json.body;
const events = body.events || [];

if (events.length === 0) {
  return [{ json: { skip: true } }];
}

const event = events[0];
const userMessage = event.message?.text || '';
const userId = event.source?.userId || '';
const replyToken = event.replyToken || '';

// Classify inquiry type
let inquiryType = 'general';
if (userMessage.includes('賃貸') || userMessage.includes('家賃')) inquiryType = 'rental';
else if (userMessage.includes('売買') || userMessage.includes('購入') || userMessage.includes('買い')) inquiryType = 'purchase';
else if (userMessage.includes('内見') || userMessage.includes('見学')) inquiryType = 'viewing';

// Extract key info with Japanese regex
const budgetMatch = userMessage.match(/(\d+)万/);
const roomsMatch = userMessage.match(/(\d+)[LDK]/);
const areaMatch = userMessage.match(/([\u3040-\u309f\u4e00-\u9faf]+[区市町村])/);

return [{
  json: {
    userId,
    replyToken,
    userMessage,
    inquiryType,
    budget: budgetMatch ? parseInt(budgetMatch[1]) : null,
    rooms: roomsMatch ? roomsMatch[0] : null,
    area: areaMatch ? areaMatch[1] : null,
    timestamp: new Date().toISOString()
  }
}];

// Parse AI response and prepare data for logging and reply
const aiResponse = $input.first().json.text || $input.first().json.response || '';
const prevData = $('Parse LINE Message').first().json;

return [{
  json: {
    ...prevData,
    aiResponse,
    isHighValue: prevData.inquiryType === 'purchase' || (prevData.budget && prevData.budget > 3000)
  }
}];
